solution_code:
#include <iostream>
#include <memory>

int main() {
    int v, should_reset;
    std::cin >> v >> should_reset;

    auto shared = std::make_shared<int>(v);
    std::weak_ptr<int> weak = shared;

    if (should_reset) {
        shared.reset();
    }

    auto locked = weak.lock();
    if (locked) {
        std::cout << "Alive: " << *locked << "\n";
    } else {
        std::cout << "Dead\n";
    }

    return 0;
}

